<div>    {{-- TOTAL --}}    <div class="mb-summary-card">        <div class="mb-label">Quote Total</div>        <div class="mb-total">            ${{ number_format($quote->total ?? 0,2) }}        </div>    </div>    {{-- NEXT STEP --}}    <div class="mb-card">        <div style="font-size:18px;font-weight:800;margin-bottom:15px;">            Next Step        </div>        <a href="#" class="mb-approve-btn">            Approve Quote        </a>    </div>    {{-- FINANCIAL --}}    <div class="mb-card">        <div style="display:flex;justify-content:space-between;margin-bottom:8px;">            <span>Subtotal</span>            <span>${{ number_format($quote->subtotal ?? 0,2) }}</span>        </div>        <div style="display:flex;justify-content:space-between;margin-bottom:8px;">            <span>Deposit</span>            <span>${{ number_format($quote->deposit_value ?? 0,2) }}</span>        </div>        <div style="display:flex;justify-content:space-between;font-weight:900;font-size:20px;">            <span>Total</span>            <span style="color:#38bdf8;">                ${{ number_format($quote->total ?? 0,2) }}            </span>        </div>    </div>    {{-- TOTAL PAID (SIMULATED FOR QUOTES) --}}    <div class="mb-card" style="text-align:center;border:1px solid rgba(56,189,248,0.2);">        <div class="mb-label">Total Paid</div>        <div style="font-size:28px;font-weight:900;color:#4ade80;">            $0.00        </div>    </div>    {{-- APPROVAL MODE --}}    <div class="mb-card">        <label style="display:flex;gap:10px;margin-bottom:10px;">            <input type="radio" checked>            <span>Customer will approve themselves</span>        </label>        <label style="display:flex;gap:10px;">            <input type="radio">            <span>I will approve manually</span>        </label>        <p style="font-size:11px;color:#94a3b8;margin-top:10px;">            Approval Mode: Choose how the customer will approve this quote.        </p>    </div>    {{-- TEST / SIMULATION BUTTONS --}}    <div class="mb-card">        <div style="font-size:14px;color:#94a3b8;margin-bottom:10px;">            Test Flow (Simulation Only)        </div>        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">            <button class="mb-btn" style="background:#1e3a8a;">                Pay Now            </button>            <button class="mb-btn" style="background:#7c2d12;">                Pay Deposit            </button>        </div>    </div></div>